// Extract Request Data - CORRECTED
const body = $input.first().json.body || {};
const binary = $input.item.binary || {};
const files = [];
// Check if files came as binary (multipart/form-data)
if (Object.keys(binary).length > 0) {
  Object.keys(binary).forEach(key => {
    const binaryData = binary[key];
    files.push({
      name: binaryData.fileName || key,
      mimeType: binaryData.mimeType || 'application/pdf',
      size: binaryData.fileSize || 0,
      extension: (binaryData.fileName || key).split('.').pop().toLowerCase(),
      data: null, // No base64 needed, using binary directly
      key: key,
      isBinary: true
    });
  });
}
// Check if files came as JSON with base64
else if (body.files && Array.isArray(body.files)) {
  body.files.forEach((file, index) => {
    files.push({
      name: file.name || `file${index}.pdf`,
      mimeType: file.mimeType || 'application/pdf',
      size: file.size || 0,
      extension: file.extension || 'pdf',
      data: file.data, // Base64 string
      key: file.key || `file${index}`,
      isBinary: false
    });
  });
}

return {
  json: {
    files: files,
    message: body.message || $input.first().json.body.query || '',
    sessionId: body.session_id || `session-${Date.now()}`,
    userId: body.user_id || 'anonymous',
    hasFiles: files.length > 0,
    hasMessage: (body.message || '').trim().length > 0,
    // Debug info
    _debug: {
      hasBinaryInput: Object.keys(binary).length > 0,
      hasJsonFiles: !!(body.files && body.files.length > 0),
      fileCount: files.length
    }
  },
  binary: binary
};

// Build classification prompt - USE BOTH USER MESSAGE AND FILE CONTENT
const requestData = $('Load Conversation History').first().json;
const patterns = $('Load Learning Patterns1').all().map(p => p.json);
const pdfContent = $('Extract PDF Content').first()?.json?.text || '';

const now = new Date();
const year = now.getFullYear();
const month = String(now.getMonth() + 1).padStart(2, '0');
const file = requestData.files[0];

let prompt = `You are an expert file classifier WITH CONVERSATION MEMORY. Respond with JSON only (no markdown).

🎯 CRITICAL: Use BOTH the user message AND file content to classify accurately!

📅 DATE: ${now.toISOString().split('T')[0]}
📁 FILE: "${file.name}" (${file.mimeType})

💬 USER MESSAGE: "${requestData.message}"
   ↑ The user's description is VERY IMPORTANT for classification!
   Use this to understand the file's purpose and context.

📄 FILE CONTENT (first 500 chars):
"${pdfContent.substring(0, 500)}..."
   ↑ Read the actual content to verify and enhance classification.

`;

// ✨ ADD CONVERSATION HISTORY
if (requestData.hasHistory) {
  prompt += `${requestData.conversationContext}

`;
}

if (patterns.length > 0) {
  prompt += `🧠 LEARNED PATTERNS (use these!):
`;
  patterns.forEach((p, i) => {
    prompt += `${i+1}. "${p.pattern_key}" → ${p.file_type} (${p.category})
`;
    prompt += `   Folder: ${p.folder_template}
`;
    prompt += `   Used ${p.usage_count}x, ${Math.round(p.confidence * 100)}% confident

`;
  });
}

prompt += `
📋 CLASSIFICATION INSTRUCTIONS:

1️⃣ **Read the USER MESSAGE** - This tells you WHY the file is being uploaded
2️⃣ **Read the FILE CONTENT** - This tells you WHAT the file actually contains
3️⃣ **Combine BOTH** - Use message for context, content for verification

Examples:
- User: "This is Ahmed's sick leave" + Content: Medical certificate → Medical/Ahmed/${year}
- User: "Invoice for equipment" + Content: Invoice details → Finance/Invoices/${year}/${month}
- User: "Warning letter" + Content: Disciplinary text → HR/Warnings/Employee/${year}

📋 RESPOND WITH JSON ONLY:
{
  "file_type": "warning|invoice|certificate|leave|request|report|...",
  "file_type_display": "Warning",
  "file_type_arabic": "تحذير",
  "category": "HR|Finance|Legal|Medical|Administrative",
  "category_arabic": "الموارد البشرية|المالية|القانونية|الطبية|الإدارية",
  "subcategory": "Disciplinary Warning|Sick Leave|Invoice|...",
  "employee_name": "Ahmed|null",
  "employee_name_normalized": "ahmed|null",
  "google_drive_folder": "HR/Warnings/Ahmed/${year}",
  "summary": "Brief summary combining user intent and file content",
  "confidence_score": 0.95,
  "language": "ar|en|mixed",
  "used_pattern": "تحذير|null",
  "used_context": false,
  "reasoning": "Classified based on user message '...' and file content '...'",
  "classification_source": "user_message_and_content"
}

FOLDER RULES:
- HR: "HR/{Subcategory}/{Employee}/${year}"
- Finance: "Finance/{Subcategory}/${year}/${month}"
- Legal: "Legal/{Subcategory}/${year}"
- Medical: "Medical/{Employee}/${year}"
- Administrative: "Administrative/{Subcategory}/${year}"

If employee name is in user message OR content, use it. Otherwise use "General".`;

return { json: { prompt } };

// Prepare for Processing - Combine data and preserve binary
const switchOutput = $input.item.json;
const convertBinary = $('Convert to Binary').item;

// Get the binary data
const binaryData = convertBinary.binary || {};

return {
  json: {
    // Keep all the important data
    files: convertBinary.json.files,
    message: convertBinary.json.message,
    sessionId: convertBinary.json.sessionId,
    userId: convertBinary.json.userId,
    hasFiles: convertBinary.json.hasFiles,
    hasMessage: convertBinary.json.hasMessage,

    // Add intent from switch
    intent: switchOutput.message.content.intent,
    intentConfidence: switchOutput.message.content.confidence
  },
  binary: binaryData  // This is critical!
};

// Prepare Conversation Update WITH CLEAN EXTRACTED CONTENT + SQL ESCAPING
const fileRecord = $('Save to Database').first().json;
const sessionData = $('Load Conversation History').first().json;
const classification = $('Classify File with AI').first().json.message.content;

// ✨ GET CLEAN EXTRACTED PDF CONTENT
const extractedPDF = $('Extract PDF Content').first()?.json;
const cleanContent = extractedPDF?.text || '';
const pageCount = extractedPDF?.pageCount || null;

// Build conversation messages
const userMessage = sessionData.message || `Uploaded file: ${fileRecord.file_name}`;
const aiMessage = `File classified as ${fileRecord.file_type_display} (${fileRecord.file_type_arabic}). ${classification.summary}`;

// Get existing history and append new messages
const existingHistory = sessionData.conversationHistory || [];
const newHistory = [
  ...existingHistory,
  {
    role: 'user',
    content: userMessage,
    file_id: fileRecord.id,
    file_name: fileRecord.file_name,
    file_type: fileRecord.file_type_display,
    intent: sessionData.intent || 'AUTO_SAVE',
    timestamp: new Date().toISOString()
  },
  {
    role: 'assistant',
    content: aiMessage,
    file_id: fileRecord.id,

    // ✨ SAVE CLEAN EXTRACTED CONTENT
    file_content: cleanContent,
    content_length: cleanContent.length,
    page_count: pageCount,

    // File metadata
    file_info: {
      id: fileRecord.id,
      uuid: fileRecord.uuid,
      name: fileRecord.file_name,
      type: fileRecord.file_type_display,
      size_bytes: fileRecord.file_size_bytes || 0,
      mime_type: fileRecord.mime_type
    },

    // Classification details
    classification: {
      type: fileRecord.file_type_display,
      type_arabic: fileRecord.file_type_arabic,
      category: fileRecord.category,
      category_arabic: classification.category_arabic,
      subcategory: classification.subcategory,
      employee: fileRecord.employee_name,
      folder: fileRecord.google_drive_folder,
      confidence: fileRecord.confidence_score,
      language: classification.language,
      summary: classification.summary,
      reasoning: classification.reasoning,
      used_pattern: classification.used_pattern,
      used_context: classification.used_context,
      classification_source: classification.classification_source  // ✅ Track if user message was used
    },

    timestamp: new Date().toISOString()
  }
];

// Create context summary (last 3 files)
const recentFiles = newHistory
  .filter(m => m.role === 'user' && m.file_name)
  .slice(-3)
  .map(m => m.file_name)
  .join(', ');

const contextSummary = `Recent files: ${recentFiles}`;

// ✅ ESCAPE FUNCTIONS FOR POSTGRESQL
function escapeSql(str) {
  if (!str) return '';
  return str.replace(/'/g, "''");
}

function escapeJson(obj) {
  const jsonStr = JSON.stringify(obj);
  return jsonStr.replace(/'/g, "''");
}

// Build SQL with proper escaping
const sql = `
INSERT INTO conversations (
    session_id, 
    user_id, 
    message_count, 
    last_message, 
    last_ai_response, 
    file_ids, 
    context_summary,
    full_history,
    last_activity,
    is_active
)
VALUES (
    '${escapeSql(sessionData.sessionId)}',
    '${escapeSql(sessionData.userId)}',
    ${newHistory.length},
    '${escapeSql(userMessage)}',
    '${escapeSql(aiMessage)}',
    ARRAY[${fileRecord.id}]::INTEGER[],
    '${escapeSql(contextSummary)}',
    '${escapeJson(newHistory)}'::jsonb,
    NOW(),
    TRUE
)
ON CONFLICT (session_id) 
DO UPDATE SET
    message_count = ${newHistory.length},
    last_message = EXCLUDED.last_message,
    last_ai_response = EXCLUDED.last_ai_response,
    file_ids = array_append(conversations.file_ids, ${fileRecord.id}),
    context_summary = EXCLUDED.context_summary,
    full_history = '${escapeJson(newHistory)}'::jsonb,
    last_activity = NOW(),
    is_active = TRUE
RETURNING 
    id, 
    session_id, 
    message_count;
`;

return {
  json: {
    sql: sql,
    fileRecord: fileRecord,
    sessionData: sessionData,
    conversationLength: newHistory.length,
    debug: {
      new_messages: 2,
      total_messages: newHistory.length,
      had_history: existingHistory.length > 0,
      content_saved: cleanContent.length > 0,
      content_length: cleanContent.length,
      pages: pageCount,
      used_escaping: true
    }
  }
};

// Parse query parameters
const query = $input.item.json.query || {};

return {
  json: {
    userId: query.user_id || 'anonymous',
    limit: parseInt(query.limit) || 20,
    offset: parseInt(query.offset) || 0,
    onlyActive: query.only_active !== 'false' // Default true
  }
};

// Format conversations for frontend
const conversations = $input.all().map(item => item.json);

const formatted = conversations.map(conv => ({
  id: conv.id,
  session_id: conv.session_id,
  title: conv.context_summary || conv.last_message?.substring(0, 50) + '...' || 'New Conversation',
  preview: conv.last_ai_response?.substring(0, 100) + '...' || '',
  message_count: conv.message_count || 0,
  file_count: conv.total_files || 0,
  last_activity: conv.last_activity,
  created_at: conv.started_at,
  is_active: conv.is_active
}));

return {
  json: {
    success: true,
    total: formatted.length,
    conversations: formatted
  }
};

// Get session_id from URL path parameter
const params = $input.item.json.params || {};
const query = $input.item.json.query || {};

return {
  json: {
    sessionId: params.session_id || query.session_id,
    includeFiles: query.include_files !== 'false', // Default true
    limit: parseInt(query.limit) || 100
  }
};

// Format full conversation history
const conv = $input.first()?.json;

if (!conv || !conv.id) {
  return {
    json: {
      success: false,
      error: 'Conversation not found'
    }
  };
}

// Parse full_history if it's a string
let messages = [];
if (conv.full_history) {
  if (typeof conv.full_history === 'string') {
    messages = JSON.parse(conv.full_history);
  } else {
    messages = conv.full_history;
  }
}

// Parse files_data if present
let files = [];
if (conv.files_data) {
  if (typeof conv.files_data === 'string') {
    files = JSON.parse(conv.files_data);
  } else {
    files = conv.files_data;
  }
}

return {
  json: {
    success: true,
    conversation: {
      id: conv.id,
      session_id: conv.session_id,
      user_id: conv.user_id,
      title: conv.context_summary || 'Conversation',
      message_count: conv.message_count,
      created_at: conv.started_at,
      last_activity: conv.last_activity,
      is_active: conv.is_active
    },
    messages: messages,
    files: files,
    stats: {
      total_messages: messages.length,
      total_files: files.length,
      user_messages: messages.filter(m => m.role === 'user').length,
      assistant_messages: messages.filter(m => m.role === 'assistant').length
    }
  }
};

const query = $input.item.json.query || {};

return {
  json: {
    userId: query.user_id || 'anonymous',
    searchTerm: query.q || query.search || '',
    category: query.category || null,
    fileType: query.file_type || null,
    fromDate: query.from_date || null,
    toDate: query.to_date || null,
    limit: parseInt(query.limit) || 20
  }
};

const results = $input.all().map(item => ({
  id: item.json.id,
  session_id: item.json.session_id,
  title: item.json.context_summary || 'Conversation',
  preview: item.json.last_ai_response?.substring(0, 150) + '...',
  message_count: item.json.message_count,
  relevance: item.json.relevance,
  last_activity: item.json.last_activity,
  created_at: item.json.started_at
}));

return {
  json: {
    success: true,
    query: $('Parse Search Query').first().json.searchTerm,
    total: results.length,
    results: results
  }
};

// Prepare upload - handles both paths
const data = $input.first().json;

// Get folder ID from either path
let folderId;
let fileName;
let fileId;
let folderPath;

if (data.finalFolderId) {
  // Coming from folder creation loop
  folderId = data.finalFolderId;
  fileName = data.fileName;
  fileId = data.fileId;
  folderPath = data.folderPath;
} else {
  // Coming from folder exists check
  folderId = data.folderId;
  fileName = data.fileName;
  fileId = data.fileId;
  folderPath = data.folderPath;
}

return {
  json: {
    folderId: folderId,
    fileName: fileName,
    fileId: fileId,
    folderPath: folderPath,
    createdFolders: data.createdFolders || [],
    fromExisting: !data.finalFolderId
  },
  binary: $('Prepare for Processing').first().binary // Get binary from original source!
};

// Save Drive Link
const fileRecord = $('Save to Database').first().json;
const driveResult = $input.first().json;
const uploadData = $('Prepare Upload').first().json;

const sql = `
UPDATE files 
SET 
    google_drive_file_id = $driveid$${driveResult.id}$driveid$,
    google_drive_web_view_link = $link$${driveResult.webViewLink}$link$,
    google_drive_folder_id = $folderid$${uploadData.folderId}$folderid$,
    google_drive_uploaded = TRUE
WHERE id = ${fileRecord.id}
RETURNING 
    id, 
    file_name, 
    google_drive_file_id, 
    google_drive_web_view_link,
    google_drive_uploaded;
`;

return {
  json: {
    sql: sql,
    driveLink: driveResult.webViewLink,
    driveFileId: driveResult.id,
    folderPath: uploadData.folderPath,
    foldersCreated: uploadData.createdFolders
  }
};

// Create Folder Path Data
const fileRecord = $('Save to Database').first().json;
const folderPath = fileRecord.google_drive_folder;
const ROOT_FOLDER_ID = 'ROOT_FOLDER_ID';

const folderParts = folderPath.split('/').filter(p => p.trim() !== '');

return {
  json: {
    folderParts: folderParts,
    currentLevel: 0,
    totalLevels: folderParts.length,
    rootFolderId: ROOT_FOLDER_ID,
    fileName: fileRecord.file_name,
    fileId: fileRecord.id,
    folderPath: folderPath,
    createdFolders: []
  },
  binary: $('Prepare for Processing').first().binary
};

// Prepare current folder level
const data = $input.first().json;
const currentLevel = data.currentLevel;
const folderName = data.folderParts[currentLevel];

// Get parent ID
let parentId;
if (currentLevel === 0) {
  parentId = data.rootFolderId;
} else {
  const createdFolders = data.createdFolders;
  parentId = createdFolders[createdFolders.length - 1].id;
}

return {
  json: {
    ...data,
    folderName: folderName,
    parentId: parentId
  },
  binary: $input.first().binary
};

// Prepare Database Insert - WITH EMBEDDING + VALIDATION ✅
const classification = $('Classify File with AI').first().json.message.content;
const fileData = $('Prepare for Processing').first().json;
const pdfContent = $('Extract PDF Content').first()?.json?.text || '';

// ✅✅✅ ADD THIS VALIDATION BLOCK ✅✅✅
// VALIDATION 1: Check content exists
if (!pdfContent) {
  throw new Error('❌ PDF extraction failed - no content found');
}

// VALIDATION 2: Check content is not too short
if (pdfContent.length < 50) {
  throw new Error(`❌ PDF content too short (${pdfContent.length} chars) - extraction may have failed`);
}

// VALIDATION 3: Check content is not the user message
const userMessage = fileData.message || '';
if (pdfContent === userMessage) {
  throw new Error('❌ PDF content equals user message - extraction failed!');
}

// VALIDATION 4: Log for debugging
console.log('✅ PDF Content Validated:', {
  fileName: fileData.files[0].name,
  contentLength: pdfContent.length,
  preview: pdfContent.substring(0, 100),
  isNotUserMessage: pdfContent !== userMessage
});
// ✅✅✅ END VALIDATION BLOCK ✅✅✅

// ✅ GET EMBEDDING
const embeddingResponse = $('Generate File Embedding').first().json;
const embedding = embeddingResponse.data[0].embedding;

const now = new Date().toISOString();

function parseFileSize(size) {
  if (typeof size === 'number') return size;
  if (typeof size === 'string') {
    const numOnly = size.replace(/[^\d.]/g, '');
    const num = parseFloat(numOnly);
    if (isNaN(num)) return 0;

    const sizeStr = size.toLowerCase();
    if (sizeStr.includes('kb')) return Math.round(num * 1024);
    if (sizeStr.includes('mb')) return Math.round(num * 1024 * 1024);
    if (sizeStr.includes('gb')) return Math.round(num * 1024 * 1024 * 1024);
    return Math.round(num);
  }
  return 0;
}

const fileSizeBytes = parseFileSize(fileData.files[0].size);

const employeeName = (classification.employee_name === 'null' || !classification.employee_name) 
  ? null 
  : classification.employee_name;

const employeeNormalized = (classification.employee_name_normalized === 'null' || !classification.employee_name_normalized) 
  ? null 
  : classification.employee_name_normalized;

let folderPath = classification.google_drive_folder;
if (!employeeName) {
  folderPath = folderPath.replace('/null/', '/General/');
}

const sql = `
INSERT INTO files (
    file_name,
    original_file_name,
    file_size_bytes,
    mime_type,
    file_extension,
    file_type,
    file_type_display,
    file_type_arabic,
    category,
    category_arabic,
    subcategory,
    employee_name,
    employee_name_normalized,
    google_drive_folder,
    content_text,
    content_summary,
    content_embedding,
    ai_classification,
    confidence_score,
    language,
    uploaded_by,
    session_id,
    created_at
) 
VALUES (
    $fname$${classification.file_type_display} - ${fileData.files[0].name}$fname$,
    $oname$${fileData.files[0].name}$oname$,
    ${fileSizeBytes},
    $mime$${fileData.files[0].mimeType}$mime$,
    $ext$${fileData.files[0].extension}$ext$,
    $ftype$${classification.file_type}$ftype$,
    $ftdisp$${classification.file_type_display}$ftdisp$,
    $ftar$${classification.file_type_arabic}$ftar$,
    $cat$${classification.category}$cat$,
    $catar$${classification.category_arabic}$catar$,
    $subcat$${classification.subcategory}$subcat$,
    ${employeeName ? `$empname$${employeeName}$empname$` : 'NULL'},
    ${employeeNormalized ? `$empnorm$${employeeNormalized}$empnorm$` : 'NULL'},
    $folder$${folderPath}$folder$,
    $content$${pdfContent.substring(0, 50000)}$content$,
    $summary$${classification.summary}$summary$,
    '[${embedding.join(',')}]'::vector,
    $aiclass$${JSON.stringify(classification)}$aiclass$::jsonb,
    ${classification.confidence_score},
    $lang$${classification.language}$lang$,
    $upby$${fileData.userId}$upby$,
    $sessid$${fileData.sessionId}$sessid$,
    NOW()
)
RETURNING 
    id, 
    uuid, 
    file_name, 
    file_type_display, 
    category,
    employee_name,
    google_drive_folder,
    confidence_score,
    LENGTH(content_text) as content_length,
    content_embedding IS NOT NULL as has_embedding;
`;

return {
  json: {
    sql: sql,
    classification: classification,
    fileData: fileData,
    embedding_dimensions: embedding.length,
    validation: {  // ✅ ADD VALIDATION INFO TO RETURN
      content_length: pdfContent.length,
      content_preview: pdfContent.substring(0, 100),
      passed_validation: true
    },
    debug: {
      original_size: fileData.files[0].size,
      parsed_size_bytes: fileSizeBytes,
      has_embedding: true
    }
  }
};

// Check if file was already uploaded
const checkResult = $('Check if Already Processed').first()?.json;
const requestData = $('Extract Request Data').first().json;

const alreadyProcessed = checkResult && checkResult.id;

if (alreadyProcessed) {
  // File already exists - return existing record
  return {
    json: {
      alreadyProcessed: true,
      existingFile: checkResult,
      action: 'skip',
      message: `File "${checkResult.file_name}" was already uploaded at ${checkResult.created_at}`
    }
    // No binary needed for skip path
  };
}

// New file - continue processing with binary data
return {
  json: {
    alreadyProcessed: false,
    action: 'process',
    ...requestData
  },
  binary: $('Extract Request Data').first().binary // Preserve binary!
};

