// Check if folder exists at this level
const searchResult = $input.first()?.json;
const prepData = $('Prepare Current Level').first().json;

const folderFound = searchResult?.files && searchResult.files.length > 0;
const existingFolderId = folderFound ? searchResult.files[0].id : null;

return {
  json: {
    ...prepData,
    folderFound: folderFound,
    existingFolderId: existingFolderId,
    needsCreation: !folderFound
  },
  binary: $input.first().binary
};

// Use existing folder ID
const data = $input.first().json;

return {
  json: {
    id: data.existingFolderId,
    name: data.folderName,
    parents: [data.parentId],
    wasExisting: true
  },
  binary: $input.first().binary
};

// Merge result from either create or use existing
const folderResult = $input.first().json;
const levelData = $('Folder Exists at Level?').first().json;

const createdFolders = [...levelData.createdFolders, {
  name: folderResult.name,
  id: folderResult.id,
  level: levelData.currentLevel,
  wasExisting: folderResult.wasExisting || false
}];

const nextLevel = levelData.currentLevel + 1;
const isComplete = nextLevel >= levelData.totalLevels;

return {
  json: {
    folderParts: levelData.folderParts,
    currentLevel: nextLevel,
    totalLevels: levelData.totalLevels,
    rootFolderId: levelData.rootFolderId,
    fileName: levelData.fileName,
    fileId: levelData.fileId,
    folderPath: levelData.folderPath,
    createdFolders: createdFolders,
    finalFolderId: folderResult.id,
    isComplete: isComplete
  },
  binary: $input.first().binary
};

// ✅ Enrich File Embedding - Include USER MESSAGE + FILE CONTENT
const classification = $('Classify File with AI').first().json.message.content;
const pdfContent = $('Extract PDF Content').first().json.text;
const requestData = $('Load Conversation History').first().json;

// ✅ BUILD ENRICHED TEXT WITH USER MESSAGE
