let filesWithContent = [];

try {
  if (conversation && conversation.full_history) {
    fullHistory = typeof conversation.full_history === 'string' 
      ? JSON.parse(conversation.full_history) 
      : conversation.full_history;

    // ✅ Extract files WITH CONTENT from assistant messages
    filesWithContent = fullHistory
      .filter(msg => msg.role === 'assistant' && msg.file_content)
      .map(msg => ({
        id: msg.file_id,
        name: msg.file_info?.name || 'Unknown',
        original_name: msg.file_info?.name || 'Unknown',
        type: msg.file_info?.type || msg.classification?.type || 'Unknown',
        category: msg.classification?.category || 'Unknown',
        employee: msg.classification?.employee || null,
        folder: msg.classification?.folder || 'Unknown',
        summary: msg.classification?.summary || msg.content,
        content: msg.file_content,  // ✅ CONTENT ALREADY IN HISTORY!
        google_drive_link: msg.file_info?.google_drive_link || null,
        date: msg.timestamp
      }));

    // Remove duplicates by file_id
    const uniqueFiles = [];
    const seenIds = new Set();
    for (const file of filesWithContent) {
      if (!seenIds.has(file.id)) {
        seenIds.add(file.id);
        uniqueFiles.push(file);
      }
    }
    filesWithContent = uniqueFiles;
  }
} catch (e) {
  console.error('Error extracting files:', e);
}

// Recent conversation context (last 10 messages)
